function solve(code: string[], businessLine: string[], isActive: boolean[]): string[] {
    // Define the order of business lines
    const businessOrder: string[] = ["electronics", "grocery", "pharmacy", "restaurant"];

    // Filter valid coupons
    const validCoupons: [string, string][] = [];
    for (let i = 0; i < code.length; i++) {
        if (!isActive[i]) {
            continue;
        }
        const codeStr = code[i];
        const businessStr = businessLine[i];

        // Check if code is valid (non-empty and contains only allowed characters)
        if (!codeStr || !/^[a-zA-Z0-9_]+$/.test(codeStr)) {
            continue;
        }

        // Check if business line is valid
        if (!businessOrder.includes(businessStr)) {
            continue;
        }

        validCoupons.push([businessStr, codeStr]);
    }

    // Sort by business line order and then by code in dictionary order
    validCoupons.sort((a, b) => {
        const businessIndexA = businessOrder.indexOf(a[0]);
        const businessIndexB = businessOrder.indexOf(b[0]);
        if (businessIndexA !== businessIndexB) {
            return businessIndexA - businessIndexB;
        }
        return a[1].localeCompare(b[1]);
    });

    // Extract the codes in the sorted order
    const result: string[] = [];
    for (const [_, code] of validCoupons) {
        result.push(code);
    }
    return result;
}
